    31→const char16_t PERCENT_SIGN = '%';
    32→const char16_t EXCLAMATION  = '!';
    33→const char16_t DOLLAR       = '$';
    34→const char16_t AMPERSAND    = '&';
    35→const char16_t OPENBRACE    = '(';
    36→const char16_t CLOSINGBRACE = ')';
    37→const char16_t EQUALS       = '=';
    38→const char16_t ATSYMBOL     = '@';
    39→// clang-format on
    40→
    41→class nsCSPParser {
    42→ public:
    43→  /**
    44→   * The CSP parser only has one main publicly accessible function, which is
    45→   * parseContentSecurityPolicy. Internally the input string is separated into
    46→   * string tokens and policy() is called, which starts parsing the policy. The
    47→   * parser calls one function after the other according the the source-list
    48→   * from http://www.w3.org/TR/CSP11/#source-list. E.g., the parser can only
    49→   * call port() after the parser has already processed any possible host in
    50→   * host(), similar to a finite state machine.
    51→   */
    52→  static nsCSPPolicy* parseContentSecurityPolicy(const nsAString& aPolicyString,
    53→                                                 nsIURI* aSelfURI,
    54→                                                 bool aReportOnly,
    55→                                                 nsCSPContext* aCSPContext,
    56→                                                 bool aDeliveredViaMetaTag,
    57→                                                 bool aSuppressLogMessages);
    58→
    59→  /**
    60→   * Check if given string is valid base64 as per CSP spec.
    61→   * https://w3c.github.io/webappsec-csp/#grammardef-base64-value
    62→   */
    63→  static bool isValidBase64Value(const nsAString& aValue);
    64→
    65→ private:
    66→  nsCSPParser(policyTokens& aTokens, nsIURI* aSelfURI,
    67→              nsCSPContext* aCSPContext, bool aDeliveredViaMetaTag,
    68→              bool aSuppressLogMessages);
    69→
    70→  ~nsCSPParser();
    71→
    72→  // Parsing the CSP using the source-list from
    73→  // http://www.w3.org/TR/CSP11/#source-list
    74→  nsCSPPolicy* policy();
    75→  void directive();
    76→  nsCSPDirective* directiveName();
    77→  void directiveValue(nsTArray<nsCSPBaseSrc*>& outSrcs);
    78→  void referrerDirectiveValue(nsCSPDirective* aDir);
    79→  void reportURIList(nsCSPDirective* aDir);
    80→  void reportGroup(nsCSPDirective* aDir);
    81→  void sandboxFlagList(nsCSPDirective* aDir);
    82→  void handleRequireTrustedTypesForDirective(nsCSPDirective* aDir);
    83→  void handleTrustedTypesDirective(nsCSPDirective* aDir);
    84→  void sourceList(nsTArray<nsCSPBaseSrc*>& outSrcs);
    85→  nsCSPBaseSrc* sourceExpression();
    86→  nsCSPSchemeSrc* schemeSource();
    87→  nsCSPHostSrc* hostSource();
    88→  nsCSPBaseSrc* keywordSource();
    89→  nsCSPNonceSrc* nonceSource();
    90→  nsCSPHashSrc* hashSource();
    91→  nsCSPHostSrc* host();
    92→  bool hostChar();
    93→  bool schemeChar();
    94→  bool port();
    95→  bool path(nsCSPHostSrc* aCspHost);
    96→
    97→  bool subHost();                        // helper function to parse subDomains
    98→  bool atValidUnreservedChar();          // helper function to parse unreserved
    99→  bool atValidSubDelimChar();            // helper function to parse sub-delims
   100→  bool atValidPctEncodedChar();          // helper function to parse pct-encoded
   101→  bool subPath(nsCSPHostSrc* aCspHost);  // helper function to parse paths
   102→
   103→  inline bool atEnd() { return mCurChar >= mEndChar; }
   104→
   105→  inline bool accept(char16_t aSymbol) {
   106→    if (atEnd()) {
   107→      return false;
   108→    }
   109→    return (*mCurChar == aSymbol) && advance();
   110→  }
   111→
   112→  inline bool accept(bool (*aClassifier)(char16_t)) {
   113→    if (atEnd()) {
   114→      return false;
   115→    }
   116→    return (aClassifier(*mCurChar)) && advance();
   117→  }
   118→
   119→  inline bool peek(char16_t aSymbol) {
   120→    if (atEnd()) {
   121→      return false;
   122→    }
   123→    return *mCurChar == aSymbol;
   124→  }
   125→
   126→  inline bool peek(bool (*aClassifier)(char16_t)) {
   127→    if (atEnd()) {
   128→      return false;
   129→    }
   130→    return aClassifier(*mCurChar);
   131→  }
   132→
   133→  inline bool advance() {
   134→    if (atEnd()) {
   135→      return false;
   136→    }
   137→    mCurValue.Append(*mCurChar++);
   138→    return true;
   139→  }
   140→
   141→  inline void resetCurValue() { mCurValue.Truncate(); }
   142→
   143→  bool atEndOfPath();
   144→  bool atValidPathChar();
   145→
   146→  void resetCurChar(const nsAString& aToken);
   147→
   148→  void logWarningErrorToConsole(uint32_t aSeverityFlag, const char* aProperty,
   149→                                const nsTArray<nsString>& aParams);
   150→
   151→  void logWarningForIgnoringNoneKeywordToConsole();
   152→
   153→  void MaybeWarnAboutIgnoredSources(const nsTArray<nsCSPBaseSrc*>& aSrcs);
   154→  void MaybeWarnAboutUnsafeInline(const nsCSPDirective& aDirective);
   155→  void MaybeWarnAboutUnsafeEval(const nsCSPDirective& aDirective);
   156→
   157→  /**
   158→   * When parsing the policy, the parser internally uses the following helper
   159→   * variables/members which are used/reset during parsing. The following
   160→   * example explains how they are used.
   161→   * The tokenizer separats all input into arrays of arrays of strings, which
   162→   * are stored in mTokens, for example:
   163→   *   mTokens = [ [ script-src, http://www.example.com, 'self' ], ... ]
   164→   *
   165→   * When parsing starts, mCurdir always holds the currently processed array of
   166→   * strings.
   167→   * In our example:
   168→   *   mCurDir = [ script-src, http://www.example.com, 'self' ]
   169→   *
   170→   * During parsing, we process/consume one string at a time of that array.
   171→   * We set mCurToken to the string we are currently processing; in the first
   172→   * case that would be: mCurToken = script-src which allows to do simple string
   173→   * comparisons to see if mCurToken is a valid directive.
   174→   *
   175→   * Continuing parsing, the parser consumes the next string of that array,
   176→   * resetting:
   177→   *   mCurToken = "http://www.example.com"
   178→   *                ^                     ^
   179→   *                mCurChar              mEndChar (points *after* the 'm')
   180→   *   mCurValue = ""
   181→   *
   182→   * After calling advance() the first time, helpers would hold the following
   183→   * values:
   184→   *   mCurToken = "http://www.example.com"
   185→   *                 ^                    ^
   186→   *                 mCurChar             mEndChar (points *after* the 'm')
   187→   *  mCurValue = "h"
   188→   *
   189→   * We continue parsing till all strings of one directive are consumed, then we
   190→   * reset mCurDir to hold the next array of strings and start the process all
   191→   * over.
   192→   */
   193→
   194→  const char16_t* mCurChar;
   195→  const char16_t* mEndChar;
   196→  nsString mCurValue;
   197→  nsString mCurToken;
   198→  nsTArray<nsString> mCurDir;
   199→
   200→  // helpers to allow invalidation of srcs within script-src and style-src
   201→  // if either 'strict-dynamic' or at least a hash or nonce is present.
   202→  bool mHasHashOrNonce;    // false, if no hash or nonce is defined
   203→  bool mHasAnyUnsafeEval;  // false, if no (wasm-)unsafe-eval keyword is used.
   204→  bool mStrictDynamic;     // false, if 'strict-dynamic' is not defined
   205→  nsCSPKeywordSrc* mUnsafeInlineKeywordSrc;  // null, otherwise invlidate()
   206→
   207→  // cache variables for child-src, frame-src and worker-src handling;
   208→  // in CSP 3 child-src is deprecated. For backwards compatibility
   209→  // child-src needs to restrict:
   210→  //   (*) frames, in case frame-src is not expicitly specified
   211→  //   (*) workers, in case worker-src is not expicitly specified
   212→  // If neither worker-src, nor child-src is present, then script-src
   213→  // needs to govern workers.
   214→  nsCSPChildSrcDirective* mChildSrc;
   215→  nsCSPDirective* mFrameSrc;
   216→  nsCSPDirective* mWorkerSrc;
   217→  nsCSPScriptSrcDirective* mScriptSrc;
   218→  nsCSPStyleSrcDirective* mStyleSrc;
   219→
   220→  // cache variable to let nsCSPHostSrc know that it's within
   221→  // the frame-ancestors directive.
   222→  bool mParsingFrameAncestorsDir;
   223→
   224→  policyTokens mTokens;
   225→  nsIURI* mSelfURI;
   226→  nsCSPPolicy* mPolicy;
   227→  nsCSPContext* mCSPContext;  // used for console logging
   228→  bool mDeliveredViaMetaTag;
   229→  bool mSuppressLogMessages;
   230→};
   231→
   232→#endif /* nsCSPParser_h_ */
   233→

