  1871→nsCSPDirective* nsCSPPolicy::matchingOrDefaultDirective(
  1872→    CSPDirective aDirective) const {
  1873→  nsCSPDirective* defaultDir = nullptr;
  1874→
  1875→  // Try to find a matching directive
  1876→  for (uint32_t i = 0; i < mDirectives.Length(); i++) {
  1877→    if (mDirectives[i]->isDefaultDirective()) {
  1878→      defaultDir = mDirectives[i];
